CREATE TABLE IF NOT EXISTS reviews (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, product_id UUID NOT NULL, vendor_id UUID, user_id UUID NOT NULL, order_id UUID, rating INTEGER NOT NULL, title VARCHAR(200), body TEXT, media JSONB DEFAULT '[]', vendor_reply TEXT, helpful_count INTEGER DEFAULT 0, status VARCHAR(20) DEFAULT 'pending', verified_purchase BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT NOW());
